// ---------------- Orders (Order Master + Manage Order) ----------------
function Orders({ supabase, setError, userRole }) {
  const [mode, setMode] = useState('create');
  const customers = useLookup(supabase, 'ledgers', setError, (l) => l.ledger_type === 'customer');
  const items = useLookup(supabase, 'items', setError);
  const empty = { date: todayStr(), ledgerId: '', itemId: '', quantity: '', rate: '', expectedDate: '', remarks: '' };
  const [form, setForm] = useState(empty);
  const { rows, load } = useSynced(supabase, 'orders', '*, ledgers(ledger_name), items(item_name)', setError, 'date');

  const save = async () => {
    if (!form.ledgerId || !form.itemId || !form.quantity) return;
    const { error } = await supabase.from('orders').insert({
      date: form.date, ledger_id: form.ledgerId, item_id: form.itemId,
      quantity: parseFloat(form.quantity), rate: form.rate ? parseFloat(form.rate) : null,
      expected_date: form.expectedDate || null, remarks: form.remarks || null, added_by: userRole,
    });
    if (error) setError(error.message); else setForm(empty);
  };

  const updateStatus = async (order, deliveredQuantity, status) => {
    const { error } = await supabase.from('orders').update({ delivered_quantity: deliveredQuantity, status }).eq('id', order.id);
    if (error) setError(error.message); else load();
  };

  const pending = rows.filter((r) => r.status !== 'fulfilled' && r.status !== 'cancelled');

  return (
    <div className="space-y-4">
      <div className="flex gap-2">
        <button onClick={() => setMode('create')} className={`px-3 py-2 rounded-lg text-sm font-semibold ${mode === 'create' ? 'bg-red-800 text-white' : 'bg-gray-100'}`}>Order Master (New Order)</button>
        <button onClick={() => setMode('manage')} className={`px-3 py-2 rounded-lg text-sm font-semibold ${mode === 'manage' ? 'bg-red-800 text-white' : 'bg-gray-100'}`}>Manage Orders ({pending.length} pending)</button>
      </div>

      {mode === 'create' && (
        <FormPanel
          title="Create Order"
          onSave={save}
          tableRows={rows}
          onDelete={async (id) => { const { error } = await supabase.from('orders').delete().eq('id', id); if (error) setError(error.message); }}
          columns={[
            { key: 'date', label: 'Date' },
            { key: 'ledger', label: 'Customer', render: (r) => r.ledgers?.ledger_name },
            { key: 'item', label: 'Item', render: (r) => r.items?.item_name },
            { key: 'quantity', label: 'Qty' },
            { key: 'delivered_quantity', label: 'Delivered' },
            { key: 'status', label: 'Status' },
          ]}
        >
          <input type="date" value={form.date} onChange={(e) => setForm((p) => ({ ...p, date: e.target.value }))} className="w-full px-3 py-2 border rounded-md" />
          <select value={form.ledgerId} onChange={(e) => setForm((p) => ({ ...p, ledgerId: e.target.value }))} className="w-full px-3 py-2 border rounded-md">
            <option value="">Select Customer</option>
            {customers.map((c) => <option key={c.id} value={c.id}>{c.ledger_name}</option>)}
          </select>
          <select value={form.itemId} onChange={(e) => setForm((p) => ({ ...p, itemId: e.target.value }))} className="w-full px-3 py-2 border rounded-md">
            <option value="">Select Item</option>
            {items.map((it) => <option key={it.id} value={it.id}>{it.item_name}</option>)}
          </select>
          <input type="number" value={form.quantity} onChange={(e) => setForm((p) => ({ ...p, quantity: e.target.value }))} placeholder="Quantity Ordered" className="w-full px-3 py-2 border rounded-md" />
          <input type="number" value={form.rate} onChange={(e) => setForm((p) => ({ ...p, rate: e.target.value }))} placeholder="Rate (₹/1000, optional)" className="w-full px-3 py-2 border rounded-md" />
          <input type="date" value={form.expectedDate} onChange={(e) => setForm((p) => ({ ...p, expectedDate: e.target.value }))} placeholder="Expected Delivery" className="w-full px-3 py-2 border rounded-md" />
          <input type="text" value={form.remarks} onChange={(e) => setForm((p) => ({ ...p, remarks: e.target.value }))} placeholder="Remarks" className="w-full px-3 py-2 border rounded-md" />
        </FormPanel>
      )}

      {mode === 'manage' && (
        <div className="bg-white rounded-lg shadow-md p-6 overflow-x-auto">
          {pending.length === 0 ? (
            <p className="text-gray-400">No pending orders</p>
          ) : (
            <table className="w-full text-sm">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-3 py-2 text-left">Date</th>
                  <th className="px-3 py-2 text-left">Customer</th>
                  <th className="px-3 py-2 text-left">Item</th>
                  <th className="px-3 py-2 text-left">Ordered</th>
                  <th className="px-3 py-2 text-left">Delivered</th>
                  <th className="px-3 py-2 text-left">Status</th>
                  <th className="px-3 py-2">Actions</th>
                </tr>
              </thead>
              <tbody>
                {pending.map((r) => (
                  <OrderRow key={r.id} order={r} onUpdate={updateStatus} />
                ))}
              </tbody>
            </table>
          )}
        </div>
      )}
    </div>
  );
}

function OrderRow({ order, onUpdate }) {
  const [delivered, setDelivered] = useState(order.delivered_quantity || 0);
  return (
    <tr className="border-b">
      <td className="px-3 py-2">{order.date}</td>
      <td className="px-3 py-2">{order.ledgers?.ledger_name}</td>
      <td className="px-3 py-2">{order.items?.item_name}</td>
      <td className="px-3 py-2">{order.quantity}</td>
      <td className="px-3 py-2">
        <input type="number" value={delivered} onChange={(e) => setDelivered(e.target.value)} className="w-20 px-2 py-1 border rounded-md" />
      </td>
      <td className="px-3 py-2 capitalize">{order.status}</td>
      <td className="px-3 py-2 text-center space-x-2">
        <button
          onClick={() => onUpdate(order, parseFloat(delivered) || 0, parseFloat(delivered) >= order.quantity ? 'fulfilled' : 'partial')}
          className="text-xs bg-green-500 text-white px-2 py-1 rounded-md"
        >
          Update
        </button>
        <button onClick={() => onUpdate(order, order.delivered_quantity || 0, 'cancelled')} className="text-xs bg-red-500 text-white px-2 py-1 rounded-md">
          Cancel
        </button>
      </td>
    </tr>
  );
}

// ---------------- Absent Voucher ----------------
function AbsentVoucher({ supabase, setError, userRole }) {
  const labourers = useLookup(supabase, 'ledgers', setError, (l) => l.ledger_type === 'labour');
  const empty = { date: todayStr(), ledgerId: '', reason: '' };
  const [form, setForm] = useState(empty);
  const { rows } = useSynced(supabase, 'absent_vouchers', '*, ledgers(ledger_name)', setError, 'date');

  const save = async () => {
    if (!form.ledgerId) return;
    const { error } = await supabase.from('absent_vouchers').insert({
      date: form.date, ledger_id: form.ledgerId, reason: form.reason || null, added_by: userRole,
    });
    if (error) setError(error.message); else setForm(empty);
  };

  const absenceCounts = {};
  for (const r of rows) {
    const name = r.ledgers?.ledger_name;
    if (!name) continue;
    absenceCounts[name] = (absenceCounts[name] || 0) + 1;
  }

  return (
    <div className="space-y-4">
      <StockGrid title="Total Absences — by Labour" entries={Object.entries(absenceCounts)} />
      <FormPanel
        title="Record Absence"
        onSave={save}
        tableRows={rows}
        onDelete={async (id) => { const { error } = await supabase.from('absent_vouchers').delete().eq('id', id); if (error) setError(error.message); }}
        columns={[
          { key: 'date', label: 'Date' },
          { key: 'ledger', label: 'Labour', render: (r) => r.ledgers?.ledger_name },
          { key: 'reason', label: 'Reason' },
        ]}
      >
        <input type="date" value={form.date} onChange={(e) => setForm((p) => ({ ...p, date: e.target.value }))} className="w-full px-3 py-2 border rounded-md" />
        <select value={form.ledgerId} onChange={(e) => setForm((p) => ({ ...p, ledgerId: e.target.value }))} className="w-full px-3 py-2 border rounded-md">
          <option value="">Select Labour</option>
          {labourers.map((l) => <option key={l.id} value={l.id}>{l.ledger_name}</option>)}
        </select>
        <input type="text" value={form.reason} onChange={(e) => setForm((p) => ({ ...p, reason: e.target.value }))} placeholder="Reason (optional)" className="w-full px-3 py-2 border rounded-md" />
      </FormPanel>
      {labourers.length === 0 && (
        <p className="text-xs text-gray-500">No labour ledgers found — add workers in Masters → Ledger with type "Labour" first.</p>
      )}
    </div>
  );
}

// ---------------- Misc Sale ----------------
function MiscSale({ supabase, setError, userRole }) {
  const customers = useLookup(supabase, 'ledgers', setError, (l) => l.ledger_type === 'customer');
  const empty = { date: todayStr(), ledgerId: '', customerName: '', description: '', quantity: '', rate: '', remarks: '' };
  const [form, setForm] = useState(empty);
  const { rows } = useSynced(supabase, 'misc_sales', '*, ledgers(ledger_name)', setError, 'date');

  const save = async () => {
    const custName = form.ledgerId ? (customers.find((c) => c.id === form.ledgerId)?.ledger_name || '') : form.customerName;
    if (!form.description) return;
    const qty = form.quantity ? parseFloat(form.quantity) : null;
    const rate = form.rate ? parseFloat(form.rate) : null;
    const amount = qty && rate ? qty * rate : null;

    const { error } = await supabase.from('misc_sales').insert({
      date: form.date, ledger_id: form.ledgerId || null, customer_name: custName || null,
      description: form.description, quantity: qty, rate, amount,
      remarks: form.remarks || null, added_by: userRole,
    });
    if (error) setError(error.message); else setForm((p) => ({ ...empty, ledgerId: p.ledgerId }));
  };

  return (
    <FormPanel
      title="Record Misc Sale"
      onSave={save}
      tableRows={rows}
      onDelete={async (id) => { const { error } = await supabase.from('misc_sales').delete().eq('id', id); if (error) setError(error.message); }}
      columns={[
        { key: 'date', label: 'Date' },
        { key: 'customer', label: 'Customer', render: (r) => r.ledgers?.ledger_name || r.customer_name || '-' },
        { key: 'description', label: 'Description' },
        { key: 'quantity', label: 'Qty', render: (r) => r.quantity ?? '-' },
        { key: 'amount', label: 'Amount (₹)', render: (r) => r.amount ?? '-' },
      ]}
    >
      <input type="date" value={form.date} onChange={(e) => setForm((p) => ({ ...p, date: e.target.value }))} className="w-full px-3 py-2 border rounded-md" />
      <select value={form.ledgerId} onChange={(e) => setForm((p) => ({ ...p, ledgerId: e.target.value }))} className="w-full px-3 py-2 border rounded-md">
        <option value="">Select Customer (or type below)</option>
        {customers.map((c) => <option key={c.id} value={c.id}>{c.ledger_name}</option>)}
      </select>
      {!form.ledgerId && (
        <input type="text" value={form.customerName} onChange={(e) => setForm((p) => ({ ...p, customerName: e.target.value }))} placeholder="Customer Name (optional)" className="w-full px-3 py-2 border rounded-md" />
      )}
      <input type="text" value={form.description} onChange={(e) => setForm((p) => ({ ...p, description: e.target.value }))} placeholder="What was sold (e.g. brick dust, scrap)" className="w-full px-3 py-2 border rounded-md" />
      <input type="number" value={form.quantity} onChange={(e) => setForm((p) => ({ ...p, quantity: e.target.value }))} placeholder="Quantity (optional)" className="w-full px-3 py-2 border rounded-md" />
      <input type="number" value={form.rate} onChange={(e) => setForm((p) => ({ ...p, rate: e.target.value }))} placeholder="Rate (optional)" className="w-full px-3 py-2 border rounded-md" />
      <input type="text" value={form.remarks} onChange={(e) => setForm((p) => ({ ...p, remarks: e.target.value }))} placeholder="Remarks" className="w-full px-3 py-2 border rounded-md" />
    </FormPanel>
  );
}
